import{l as e,a,c as n,a6 as i}from"./chunks/framework.C0d1FTMf.js";const h=JSON.parse('{"title":"Agent Skills","description":"","frontmatter":{},"headers":[],"relativePath":"ai/skill/agent-skills.md","filePath":"ai/skill/agent-skills.md"}'),o={name:"ai/skill/agent-skills.md"};function s(r,t,l,p,g,d){return a(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="agent-skills" tabindex="-1">Agent Skills <a class="header-anchor" href="#agent-skills" aria-label="Permalink to &quot;Agent Skills&quot;">​</a></h1><h2 id="why" tabindex="-1">why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;why&quot;">​</a></h2><p><a href="https://github.com/addyosmani/agent-skills" target="_blank" rel="noreferrer">Agent Skills</a> 是一套生成级别的工作流，但是起了一个和 Agent Skill 容易起误解的名字，前者是名为 Agent Skills 的工作流/技能集，后者是智能助手中的技能概念。</p><p>Agent Skills 项目来自 Google 内部的工程负责人，由 Google 内部验证过的工程文化整理而来。</p><h2 id="how" tabindex="-1">how <a class="header-anchor" href="#how" aria-label="Permalink to &quot;how&quot;">​</a></h2><p>Agent Skills 将工作流分为以下 7 个阶段：spec -&gt; plan -&gt; build -&gt; test -&gt; review -&gt; simplify -&gt; ship。</p><p>而每个阶段又由多个技能来实现，技能遵循统一模板，确保 AI 行为可预测、可审核、可重复。</p><h2 id="what" tabindex="-1">what <a class="header-anchor" href="#what" aria-label="Permalink to &quot;what&quot;">​</a></h2><h3 id="○-技能模板" tabindex="-1">○ 技能模板 <a class="header-anchor" href="#○-技能模板" aria-label="Permalink to &quot;○ 技能模板&quot;">​</a></h3><ul><li><strong>Frontmatter</strong>：定义技能名称和一句话描述，用于自动发现和路由</li><li><strong>Overview</strong>：简要说明这个技能解决什么问题，让 AI 快速判断是否匹配</li><li><strong>When to Use</strong>：明确的触发条件</li><li><strong>Process</strong>：分步工作流，每一步都有具体操作和中间产出</li><li><strong>Rationalizations</strong>：常见的偷懒借口（如“这个改动太小，不需要写测试”）+ 反驳理由，防止 AI 跳过关键步骤</li><li><strong>Red Flags</strong>：警告信号，当出现这些迹象时立即停止当前做法并重新评估</li><li><strong>Verification</strong>：完成技能后必须满足的证据（测试通过、构建成功、运行时数据等）</li></ul><h3 id="○-start" tabindex="-1">○ start <a class="header-anchor" href="#○-start" aria-label="Permalink to &quot;○ start&quot;">​</a></h3><p><strong>using-agent-skills</strong>：根据输入内容选择匹配的技能</p><h3 id="○-spec" tabindex="-1">○ spec <a class="header-anchor" href="#○-spec" aria-label="Permalink to &quot;○ spec&quot;">​</a></h3><p><strong>interview-me</strong>：追问需求，直到对目标的理解达到约 95% 的置信度</p><p><strong>idea-refine</strong>：运用结构化的发散与收敛思维，将模糊的初始想法逐步打磨成具体、可执行的提案</p><p><strong>spec-driven-development</strong>：在编写任何代码之前，强制输出一份完整的产品需求文档（PRD），确保代码的编写基于明确的设计和边界条件</p><h3 id="○-plan" tabindex="-1">○ plan <a class="header-anchor" href="#○-plan" aria-label="Permalink to &quot;○ plan&quot;">​</a></h3><p><strong>planning-and-task-breakdown</strong>：根据 spec，拆分独立可验证的小任务，并为每个任务定义清晰的验收标准和执行顺序</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>提示词示例</p><ul><li>根据 spec 拆分任务，严格遵循 planning-and-task-breakdown 技能</li></ul></div><h3 id="○-build" tabindex="-1">○ build <a class="header-anchor" href="#○-build" aria-label="Permalink to &quot;○ build&quot;">​</a></h3><p><strong>incremental-implementation</strong>：薄的垂直切片——实现、测试、验证、提交。特性标志、安全默认值、可回滚的变更。当任何变更涉及多个文件时使用。</p><p><strong>test-driven-development</strong>：强制执行“红-绿-重构”的TDD流程，在编写功能代码前先编写失败的测试，以此来驱动设计和保证代码可测性</p><p><strong>context-engineering</strong>：在正确的时间向智能体提供正确的信息——规则文件、上下文打包、MCP 集成。在开始会话、切换任务或输出质量下降时使用。</p><p><strong>source-driven-development</strong>：要求所有框架或库的使用决策都必须基于其官方文档，并在代码中引用来源，避免AI产生“幻觉”或使用过时的API</p><p><strong>doubt-driven-development</strong>：对每个进行中的非平凡决策进行对抗性的“全新上下文”审查：CLAIM → EXTRACT → DOUBT → RECONCILE → STOP，并可选择用户授权的跨模型升级。当风险高（生产、安全、不可逆）、在不熟悉的代码中工作、或现在验证比以后调试更便宜时使用。</p><p><strong>frontend-ui-engineering</strong>：组件架构、设计系统、状态管理、响应式设计、WCAG 2.1 AA 可访问性。在构建或修改用户面向的界面时使用。</p><p><strong>api-and-interface-design</strong>：契约优先设计、Hyrum&#39;s Law、单版本规则、错误语义、边界验证。在设计 API、模块边界或公共接口时使用。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>提示词示例</p><ul><li>开始拆分实现，严格遵循 incremental-implementation 技能</li><li>找出开发方案的问题，严格遵循 doubt-driven-development 技能</li></ul></div><h3 id="○-test" tabindex="-1">○ test <a class="header-anchor" href="#○-test" aria-label="Permalink to &quot;○ test&quot;">​</a></h3><p><strong>browser-testing-with-devtools</strong>：利用Chrome DevTools MCP协议，让AI能实时获取浏览器中的DOM、控制台日志、网络请求和性能数据，进行真实验证</p><p><strong>debugging-and-error-recovery</strong>：遵循五步故障排查法（复现→定位→简化→修复→防护），在面对错误时提供系统化的解决路径</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>提示词示例</p><ul><li>定位问题根因，严格遵循 debugging-and-error-recovery 技能</li></ul></div><h3 id="○-review" tabindex="-1">○ review <a class="header-anchor" href="#○-review" aria-label="Permalink to &quot;○ review&quot;">​</a></h3><p><strong>code-review-and-quality</strong>：提供一套五维度的代码审查标准，强调约100行代码的变更大小控制，并使用严重程度标签（如“建议”、“可选”）来组织反馈</p><p><strong>code-simplification</strong>：遵循“契斯特顿围栏”原则，在简化代码的同时确保其行为完全不变，目标不是减少行数，而是提升可读性和可维护性</p><p><strong>security-and-hardening</strong>：建立基于OWASP Top 10的安全检查清单，并实施三层边界系统，以防止常见的安全漏洞</p><p><strong>performance-optimization</strong>：强调“先测量，再优化”，并设定Core Web Vitals等关键性能指标目标，通过分析来识别和修复性能瓶颈</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>提示词示例</p><ul><li>简化代码，严格遵循 code-simplification 技能</li></ul></div><h3 id="○-ship" tabindex="-1">○ ship <a class="header-anchor" href="#○-ship" aria-label="Permalink to &quot;○ ship&quot;">​</a></h3><p><strong>git-workflow-and-versioning</strong>：推行基于主干开发的策略，并保持原子化提交。这套工作流旨在让每一次代码变更都可追溯、易管理，并将风险控制在最小范围。</p><p><strong>ci-cd-and-automation</strong>：落实“尽早集成，更快交付”的理念，建立包含质量门禁的流水线，并提供清晰的失败反馈</p><p><strong>deprecation-and-migration</strong>：将代码视为需要管理的“负债”，通过评估移除成本、计划安全删除和执行用户迁移，系统地处理技术债务</p><p><strong>documentation-and-adrs</strong>：强调记录决策的原因，而非结果。通过使用架构决策记录（ADR）来捕捉重大技术决策的上下文、约束条件和权衡过程</p><p><strong>shipping-and-launch</strong>：提供一份包含发布前检查清单、特性标志生命周期管理和回滚流程的部署指南，确保功能能够安全、可控地上线。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>提示词示例</p><ul><li>本地提交代码，严格遵循 git-workflow-and-versioning 技能</li><li>记录会话重大决策，严格遵循 documentation-and-adrs 技能</li></ul></div>',45)])])}const u=e(o,[["render",s]]);export{h as __pageData,u as default};
